THE CLAIM:
{
 "title": "Year-1 capture of 1% is really a 3-year total; too high",
 "narrative": "The model says the venture wins 1% of its serviceable market in Year 1. But the benchmarks behind that 1% describe capture over 1 to 5 years, and the one worked example in them lands at 0.1% of SAM. Because the venture is pre-launch and only sells for part of Year 1, the true number is a fraction of the back half of the year. The Year-1 figure is 2 to 3 times too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Benchmarks define the 1% share as accruing over years.",
   "refs": [
    "digest:obtainable-benchmark#c1",
    "digest:obtainable-benchmark#c5",
    "digest:obtainable-benchmark#c6",
    "ledger:obtainableFactor"
   ]
  },
  {
   "step": "propagation",
   "text": "The one worked example yields just 0.1% of SAM.",
   "refs": [
    "digest:obtainable-benchmark#c7",
    "digest:obtainable-benchmark#c10"
   ]
  },
  {
   "step": "propagation",
   "text": "Pre-launch venture sells only 6 to 9 months in Year 1.",
   "refs": [
    "profile:Stage",
    "profile:What obtainable horizon should Year-1 (YAM) assume?"
   ]
  },
  {
   "step": "model-impact",
   "text": "A 1% factor overstates real Year-1 capture 2 to 3 times.",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "A comparable early-stage data-center hardware entrant documented capturing at least 1% of its serviceable market within its first 12 months from launch.",
 "category": "fact",
 "evidence": [
  {
   "title": "TAM vs SAM vs SOM: Definitions, Formulas & 2026 Guide",
   "sourceType": "industry-report",
   "publisher": "Prospeo",
   "date": null,
   "excerpt": "SOM (Serviceable Obtainable Market): What you'll realistically capture in the next 36 months given your team, budget, and competitive position. ... What's a realistic SOM? 1-5% of SAM over 36 months for early-stage companies.",
   "url": "https://prospeo.io/s/tam-vs-sam-vs-som",
   "attached": true
  },
  {
   "title": "Serviceable Obtainable Market (SOM): PM Definition",
   "sourceType": "industry-report",
   "publisher": "IdeaPlan",
   "date": "2024-01-01",
   "excerpt": "SOM is the portion of the SAM that a company can realistically capture in the near term, typically within one to three years. ... For early-stage companies, SOM is typically 1-5% of SAM.",
   "url": "https://www.ideaplan.io/glossary/serviceable-obtainable-market-som",
   "attached": true
  },
  {
   "title": "Addressable Market Explained: TAM, SAM, SOM in 2026",
   "sourceType": "industry-report",
   "publisher": "Prospeo",
   "date": null,
   "excerpt": "SOM is what you'll capture in the near term - typically modeled over 1-3 years - and it's the number investors scrutinize hardest.",
   "url": "https://prospeo.io/s/addressable-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

